#!/usr/bin/env python3
"""Sample Python module for tree-sitter exploration."""

import os
from typing import Optional, List


class DataProcessor:
    """Process data with various transformations."""

    def __init__(self, name: str):
        """Initialize the processor."""
        self.name = name
        self._cache = {}

    def process(self, data: List[str]) -> List[str]:
        """Process a list of strings.

        Args:
            data: Input strings to process

        Returns:
            Processed strings
        """
        return [self._transform(item) for item in data]

    def _transform(self, item: str) -> str:
        """Transform a single item."""
        if item in self._cache:
            return self._cache[item]
        result = item.upper().strip()
        self._cache[item] = result
        return result


def standalone_function(x: int, y: int) -> int:
    """A standalone function outside any class."""

    def nested_helper(val: int) -> int:
        """A nested function inside standalone_function."""
        return val * 2

    return nested_helper(x) + nested_helper(y)


if __name__ == "__main__":
    processor = DataProcessor("main")
    result = processor.process(["hello", "world"])
    print(result)

